import sys
input = sys.stdin.readline

def main():
    q = int(input())
    queries = []
    for _ in range(q):
        line = input().split()
        if line[0] == '1':
            queries.append((1, int(line[1])))
        else:
            queries.append((2, int(line[1]), int(line[2])))

    # Process in reverse: maintain a mapping cur where cur[v] = current final value of v
    cur = {}

    result = []
    for i in range(len(queries) - 1, -1, -1):
        query = queries[i]
        if query[0] == 1:
            x = query[1]
            result.append(cur.get(x, x))
        else:
            x, y = query[1], query[2]
            # Replace x with y: so x should map to whatever y currently maps to
            cur[x] = cur.get(y, y)

    result.reverse()
    print(*result)

main()
